```{ojs}
//| echo: false

s3_scores = {
  const arr = [];
  for (let i = 0; i < nMethods; i++) {
    let ess_unmet = 0;
    let ess_unknown = 0;
    let fscore = 0;
    let fmax = 0;

    for (let q = 0; q < 15; q++) {
      const req = s3_req_matrix[q][i];
      const ans = s3_answers[q];
      if (req > 0) {
        fmax += req;
        if (ans < 0) {
          if (req >= 1) ess_unknown++;
        } else if (ans === 0) {
          if (req >= 1) ess_unmet++;
        } else {
          fscore += req * ans;
        }
      }
    }

    const sc = fmax > 0 ? Math.round((fscore / fmax) * 100) : 100;
    arr.push({
      name: methodNames[i], type: methodTypes[i], chapter: methodChapters[i],
      score1: s2_scores[i].score1, score2: s2_scores[i].score2, score3: sc,
      ess_unmet: ess_unmet, ess_unknown: ess_unknown, idx: i
    });
  }
  return arr;
}
```

