## Resultado combinado {#sec-autodiag-resultado}

```{ojs}
//| echo: false

combined = {
  const arr = [];
  for (let i = 0; i < nMethods; i++) {
    const m = s3_scores[i];
    const s1 = m.score1 || 0;
    const s2 = m.score2 || 0;
    const s3 = m.score3 || 0;
    const penalty = m.ess_unmet > 0 ? 0.5 : 1;
    const score = Math.round((0.40 * s1 + 0.25 * s2 + 0.35 * s3) * penalty);
    arr.push({name: m.name, type: m.type, chapter: m.chapter, score1: s1, score2: s2, score3: s3, ess_unmet: m.ess_unmet, ess_unknown: m.ess_unknown, combined: score});
  }
  arr.sort((a, b) => b.combined - a.combined);
  return arr;
}
```

